#pragma once
static const char *THERMOWORK_UI_HTML = "<!doctype html><html><body style='background:#111;color:#eee;font-family:sans-serif'><h1>ThermoWerk ESP32-S3</h1><div id=s></div><button onclick='f(100)'>SSR 100%</button><button onclick='g(1)'>GPIO HIGH</button><button onclick='g(0)'>GPIO LOW</button><script>async function u(){let r=await fetch('/api/status');let j=await r.json();s.innerText=JSON.stringify(j,null,2)} async function f(d){await fetch('/api/test',{method:'POST',body:JSON.stringify({duty:d})});u()} async function g(l){await fetch('/api/gpio_test',{method:'POST',body:JSON.stringify({action:\"set\",level:l})});u()} setInterval(u,1000);u();</script></body></html>";
